// Suporta: Meta Business API, 360dialog e Evolution API
const body = $json.body || $json;

let from = '';
let messageText = '';
let messageType = 'text';
let contactName = '';

try {
  // Meta Business API format
  if (body.entry) {
    const value = body.entry[0].changes[0].value;
    const msg = value.messages[0];
    from = msg.from;
    messageType = msg.type;
    messageText = msg.type === 'text' ? msg.text.body : '';
    contactName = value.contacts?.[0]?.profile?.name || '';
  }
  // 360dialog format
  else if (body.messages) {
    const msg = body.messages[0];
    from = msg.from;
    messageType = msg.type;
    messageText = msg.type === 'text' ? msg.text.body : '';
    contactName = body.contacts?.[0]?.profile?.name || '';
  }
  // Evolution API format
  else if (body.data) {
    const msg = body.data;
    from = msg.key.remoteJid.replace('@s.whatsapp.net', '');
    messageType = msg.message?.conversation ? 'text' : 'other';
    messageText = msg.message?.conversation || msg.message?.extendedTextMessage?.text || '';
    contactName = msg.pushName || '';
  }
} catch(e) {
  messageText = '';
  messageType = 'error';
}

// Limpar número de telefone
from = from.replace(/[^0-9]/g, '');

return [{
  json: {
    from,
    messageText: messageText.trim(),
    messageType,
    contactName,
    receivedAt: new Date().toISOString()
  }
}];

const result = $json;
const deal = result.results[0];
const inbound = $('Extrair Dados da Mensagem').first().json;

return [{
  json: {
    dealId: deal.id,
    dealName: deal.properties.dealname || '',
    contatoNome: deal.properties.contato_nome || inbound.contactName || 'Lead',
    contatoWhatsapp: deal.properties.contato_whatsapp || inbound.from,
    contatoEmail: deal.properties.contato_email || '',
    segmento: deal.properties.segmento || '',
    sdrEstado: deal.properties.sdr_estado || 'EM_CONVERSA',
    sdrHistorico: deal.properties.sdr_historico || '[]',
    sdrTentativas: parseInt(deal.properties.sdr_tentativas || '0'),
    sdrPontoDor: deal.properties.sdr_ponto_dor || '',
    sdrGancho: deal.properties.sdr_gancho || '',
    mensagemAtual: inbound.messageText,
    from: inbound.from,
    receivedAt: inbound.receivedAt,
    isNew: false
  }
}];

const deal = $json;
const inbound = $('Extrair Dados da Mensagem').first().json;

return [{
  json: {
    dealId: deal.id,
    dealName: deal.properties.dealname || '',
    contatoNome: inbound.contactName || 'Lead',
    contatoWhatsapp: inbound.from,
    contatoEmail: '',
    segmento: '',
    sdrEstado: 'EM_CONVERSA',
    sdrHistorico: '[]',
    sdrTentativas: 0,
    sdrPontoDor: '',
    sdrGancho: '',
    mensagemAtual: inbound.messageText,
    from: inbound.from,
    receivedAt: inbound.receivedAt,
    isNew: true
  }
}];

const d = $json;

// Parse histórico
let historico = [];
try {
  historico = JSON.parse(d.sdrHistorico || '[]');
} catch(e) { historico = []; }

// Montar messages array (últimas 10 trocas = 20 msgs)
const ultimas = historico.slice(-20);
const messages = [];

for (const msg of ultimas) {
  if (msg.role === 'lead') {
    messages.push({ role: 'user', content: msg.content });
  } else {
    // Reconstruir JSON de NOVA para manter formato consistente
    messages.push({
      role: 'assistant',
      content: JSON.stringify({
        message: msg.content,
        action: msg.action || 'reply',
        new_estado: msg.estado || 'EM_CONVERSA',
        internal_note: msg.note || ''
      })
    });
  }
}
// Adicionar mensagem atual
messages.push({ role: 'user', content: d.mensagemAtual });

const ehNovoLead = d.isNew || historico.length === 0;

const systemPrompt = `Você é NOVA, representante comercial da Carbon Films — agência de marketing visual cinematográfico em Santa Catarina, Brasil.

IDENTIDADE: Calorosa, direta, consultiva. Não é um bot genérico — é a melhor representante comercial que a agência poderia ter. Se perguntarem se é IA: "Sou uma assistente de IA da Carbon Films, aqui para garantir a melhor experiência desde o primeiro contato."

MERCADO SC: Direto ao ponto, desconfia de promessas, decide com cautela. Menos floreios, mais objetividade.

FRAMEWORK:
- Cada conversa tem um próximo passo claro. Nunca termine sem definir próximo passo.
- O cliente é o herói, Carbon Films é o guia. Fale sobre o problema DELE, não sobre o quanto a agência é boa.
- Escuta o que dizem E o que não dizem. Uma pergunta por mensagem.

REGRAS DE ESCRITA:
- Início obrigatório: [NOVA]:
- Máximo 4 parágrafos por mensagem WhatsApp
- UMA pergunta por mensagem
- 1-2 emojis no máximo, nunca no início de frase séria
- Sem jargão: "funil", "tráfego", "growth" só se o lead usou primeiro
- Aberturas diretas — nunca "Que ótimo!" sem substância
- Nunca envie 2 mensagens antes do lead responder

FLUXO DE CONVERSA:
${ehNovoLead ? '→ LEAD NOVO: cumprimentar e fazer UMA pergunta de abertura sobre o desafio principal' : `→ ESTADO ATUAL: ${d.sdrEstado}`}
1. Qualificar: coletar nome completo, empresa, segmento, objetivo principal, como chegou
2. Se qualificado → propor reunião diagnóstico 45min via Google Meet
3. Quando lead confirmar reunião → usar action: book_meeting

PLAYBOOK DE OBJEÇÕES SC:
- "Está caro": perguntar se o desafio ainda é real, não reduzir preço
- "Vou pensar": definir data de retorno, nunca pressionar
- "Tive experiência ruim": ouvir o que aconteceu antes de defender a Carbon
- "Garantia de resultado?": honestidade sobre variáveis + garantia de processo

CONTEXTO DO LEAD:
- Nome: ${d.contatoNome || 'Desconhecido'}
- Empresa: ${d.dealName || 'Não identificada'}
- Segmento: ${d.segmento || 'Não identificado'}
- Ponto de dor: ${d.sdrPontoDor || 'Não identificado ainda'}
- Gancho: ${d.sdrGancho || 'Nenhum ainda'}
- Tentativas de contato: ${d.sdrTentativas}

NUNCA:
- Citar preço sem proposta aprovada
- Prometer resultados específicos
- Fazer concessões sem escalar para Yan

AÇÕES DISPONÍVEIS:
- reply: resposta normal de conversa
- escalate_yan: situação que Yan precisa ver (budget alto, indicação estratégica, crise)
- book_meeting: lead CONFIRMOU interesse em reunião OU aceitou horário proposto
- mark_qualified: lead passou qualificação completa (tem nome, empresa, objetivo claro)
- mark_cold: lead claramente desinteressado (pediu para não entrar em contato)

RESPOSTA OBRIGATÓRIA — JSON VÁLIDO APENAS:
{"message":"texto WhatsApp (sem markdown)","action":"reply","new_estado":"EM_CONVERSA","meeting_datetime":"","internal_note":"nota interna"}

Campos:
- message: pronto para enviar, sem ** ou #
- action: uma das 5 opções acima
- new_estado: EM_CONVERSA | QUALIFICADO | AGUARDANDO_YAN | REUNIAO_PROPOSTA | REUNIAO_CONFIRMADA | ENCERRADO | LEAD_FRIO
- meeting_datetime: ISO8601 quando action=book_meeting (ex: 2026-05-07T14:00:00-03:00), vazio caso contrário
- internal_note: resumo para Yan (não vai para o lead)`;

return [{
  json: {
    ...d,
    claudeMessages: messages,
    claudeSystemPrompt: systemPrompt,
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 700,
      system: systemPrompt,
      messages: messages
    }),
    historicoAtual: historico
  }
}];

const response = $json;
const prev = $('Montar Prompt NOVA').first().json;

let parsed = {
  message: '[NOVA]: Olá! Recebi sua mensagem. Pode me dar um instante? Retorno em breve.',
  action: 'reply',
  new_estado: prev.sdrEstado || 'EM_CONVERSA',
  meeting_datetime: '',
  internal_note: 'Erro ao parsear resposta Claude'
};

try {
  let rawText = response.content[0].text.trim();
  // Remove markdown code blocks se existir
  rawText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(rawText);
} catch(e) {
  // Se Claude retornou texto puro (sem JSON), usar como mensagem
  try {
    const rawText = response.content[0].text.trim();
    parsed.message = rawText;
    parsed.internal_note = 'Resposta sem JSON estruturado — usando texto bruto';
  } catch(e2) {}
}

// Atualizar histórico com nova troca
let historico = prev.historicoAtual || [];
historico.push({
  role: 'lead',
  content: prev.mensagemAtual,
  ts: prev.receivedAt
});
historico.push({
  role: 'nova',
  content: parsed.message,
  action: parsed.action,
  estado: parsed.new_estado,
  note: parsed.internal_note,
  ts: new Date().toISOString()
});
// Manter apenas as últimas 30 entradas (15 trocas)
if (historico.length > 30) historico = historico.slice(-30);

// Calcular próximo follow-up (3 dias a partir de agora)
const agora = new Date();
const d3 = new Date(agora.getTime() + 3 * 24 * 60 * 60 * 1000);

return [{
  json: {
    ...prev,
    parsedAction: parsed.action,
    parsedMessage: parsed.message,
    parsedNewEstado: parsed.new_estado,
    parsedMeetingDatetime: parsed.meeting_datetime || '',
    parsedInternalNote: parsed.internal_note || '',
    novoHistorico: JSON.stringify(historico),
    nextFollowupDate: d3.toISOString().split('T')[0]
  }
}];

const d = $json;
return [{
  json: {
    ...d,
    yanAlertBody: JSON.stringify({
      to: $vars.YAN_WHATSAPP,
      type: 'text',
      text: { body: `[CEO-ATLAS]: ⚠️ ESCALAR PARA YAN\n\nLead: ${d.contatoNome} (${d.dealName})\nWhatsApp: ${d.contatoWhatsapp}\nÚltima msg: "${d.mensagemAtual}"\nAção sugerida: ${d.parsedInternalNote}\n\nDeal HubSpot: #${d.dealId}` }
    })
  }
}];

const evento = $json;
const prev = $('Parsear Resposta Claude').first().json;

const meetLink = evento.conferenceData?.entryPoints?.find(e => e.entryPointType === 'video')?.uri || evento.hangoutLink || 'Link gerado em breve';

const dataHora = new Date(evento.start.dateTime);
const dataFormatada = dataHora.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo', weekday: 'long', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });

return [{
  json: {
    ...prev,
    meetLink,
    meetEventId: evento.id,
    meetDatetime: evento.start.dateTime,
    parsedMessage: `[NOVA]: Reunião confirmada! 🎉\n\n📅 ${dataFormatada}\n🔗 ${meetLink}\n\nFico te esperando. Qualquer dúvida até lá, estou aqui!`,
    parsedNewEstado: 'REUNIAO_CONFIRMADA'
  }
}];
